import { TextStyle } from 'react-native';

export const fonts = {
  primary: 'Libre Baskerville', // For branding, logo, special headings
  secondary: 'Montserrat',     // For body, buttons, labels, etc.
};

export const typography: { [key: string]: TextStyle } = {
  logo: {
    fontFamily: fonts.primary,
    fontStyle: 'italic',
    fontWeight: '500',
    fontSize: 60,
    letterSpacing: -2,
    textAlign: 'left',
    transform: [{ scaleY: 1.3 }],
    color: '#000',
  },
  heading: {
    fontFamily: fonts.primary,
    fontStyle: 'italic',
    fontWeight: '500',
    fontSize: 28,
    color: '#000',
  },
  subheading: {
    fontFamily: fonts.secondary,
    fontWeight: '600',
    fontSize: 20,
    color: '#000',
  },
  body: {
    fontFamily: fonts.secondary,
    fontWeight: '400',
    fontSize: 16,
    color: '#000',
  },
  label: {
    fontFamily: fonts.secondary,
    fontWeight: '500',
    fontSize: 14,
    color: '#757575',
  },
  button: {
    fontFamily: fonts.secondary,
    fontWeight: '700',
    fontSize: 16,
    color: '#fff',
  },
  caption: {
    fontFamily: fonts.secondary,
    fontWeight: '400',
    fontSize: 12,
    color: '#757575',
  },
};
